import{_ as t,o as a,c as n,ag as o}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Company Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/company.md","filePath":"settings/company.md"}'),r={name:"settings/company.md"};function i(s,e,l,d,c,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="company-settings" tabindex="-1">Company Settings <a class="header-anchor" href="#company-settings" aria-label="Permalink to &quot;Company Settings&quot;">​</a></h1><p>Configure your business information, branding, financial defaults, and enabled features.</p><h2 id="accessing-settings" tabindex="-1">Accessing settings <a class="header-anchor" href="#accessing-settings" aria-label="Permalink to &quot;Accessing settings&quot;">​</a></h2><p>Navigate to <strong>Company</strong> in the sidebar to access all company-level settings. The settings are organized into sections.</p><h2 id="business-information" tabindex="-1">Business information <a class="header-anchor" href="#business-information" aria-label="Permalink to &quot;Business information&quot;">​</a></h2><h3 id="company-details" tabindex="-1">Company details <a class="header-anchor" href="#company-details" aria-label="Permalink to &quot;Company details&quot;">​</a></h3><ul><li><strong>Company name</strong> — Your registered business name (appears on all documents)</li><li><strong>Address</strong> — Street, postal code, city, country</li><li><strong>Contact email</strong> — Primary business email</li><li><strong>Phone</strong> — Business phone number</li></ul><h3 id="registration" tabindex="-1">Registration <a class="header-anchor" href="#registration" aria-label="Permalink to &quot;Registration&quot;">​</a></h3><ul><li><strong>VAT number</strong> — Your VAT registration (e.g., NL123456789B01)</li><li><strong>Chamber of Commerce</strong> — Business registration number</li><li><strong>IBAN</strong> — Bank account for receiving payments</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Address autocomplete is available — start typing and select from suggestions powered by Google Maps.</p></div><h2 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h2><h3 id="logo" tabindex="-1">Logo <a class="header-anchor" href="#logo" aria-label="Permalink to &quot;Logo&quot;">​</a></h3><p>Upload your company logo to use on:</p><ul><li>Invoice and quote PDFs</li><li>Email communications</li><li>Customer portal</li><li>Public business page</li></ul><p>Supported formats: PNG, JPG, SVG. Use a high-resolution image with a transparent background for best results.</p><h3 id="colors" tabindex="-1">Colors <a class="header-anchor" href="#colors" aria-label="Permalink to &quot;Colors&quot;">​</a></h3><p>Set your brand accent color. This is used on:</p><ul><li>PDF documents</li><li>Email templates</li><li>Customer-facing pages</li></ul><h2 id="financial-defaults" tabindex="-1">Financial defaults <a class="header-anchor" href="#financial-defaults" aria-label="Permalink to &quot;Financial defaults&quot;">​</a></h2><h3 id="currency" tabindex="-1">Currency <a class="header-anchor" href="#currency" aria-label="Permalink to &quot;Currency&quot;">​</a></h3><p>Set your default currency (EUR by default). This applies to new invoices and quotes.</p><h3 id="payment-terms" tabindex="-1">Payment terms <a class="header-anchor" href="#payment-terms" aria-label="Permalink to &quot;Payment terms&quot;">​</a></h3><p>Set the default number of days until an invoice is due. Common values:</p><ul><li><strong>14 days</strong> — Two weeks</li><li><strong>30 days</strong> — One month</li><li><strong>60 days</strong> — Two months</li></ul><p>You can override this per invoice.</p><h3 id="invoice-numbering" tabindex="-1">Invoice numbering <a class="header-anchor" href="#invoice-numbering" aria-label="Permalink to &quot;Invoice numbering&quot;">​</a></h3><p>Customize how invoice numbers are generated:</p><ul><li><strong>Prefix</strong> — Text before the number (e.g., <code>INV-</code>, <code>2024-</code>)</li><li><strong>Starting number</strong> — The first number in the sequence</li><li><strong>Auto-increment</strong> — Numbers increase automatically</li></ul><h2 id="features-toggle" tabindex="-1">Features toggle <a class="header-anchor" href="#features-toggle" aria-label="Permalink to &quot;Features toggle&quot;">​</a></h2><p>Enable or disable optional modules:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Objects / Assets</strong></td><td>Rental property and asset management</td></tr><tr><td><strong>Contracts</strong></td><td>Recurring service and rental contracts</td></tr><tr><td><strong>Projects</strong></td><td>Project-based work tracking</td></tr><tr><td><strong>Quotes</strong></td><td>Quotation management</td></tr><tr><td><strong>Reverse charge</strong></td><td>Intra-EU B2B invoicing</td></tr><tr><td><strong>AI suggestions</strong></td><td>Smart categorization recommendations</td></tr><tr><td><strong>Receipt scanning</strong></td><td>OCR expense entry</td></tr><tr><td><strong>Text check</strong></td><td>Grammar and spelling checking</td></tr></tbody></table><p>Disabled modules are hidden from the navigation to keep your workspace focused.</p><h2 id="pdf-template" tabindex="-1">PDF template <a class="header-anchor" href="#pdf-template" aria-label="Permalink to &quot;PDF template&quot;">​</a></h2><p>Customize the layout and appearance of your generated PDFs:</p><ul><li>Field positioning</li><li>Information visibility</li><li>Font and sizing</li><li>Logo placement</li></ul><p>Access the full <strong>PDF Editor</strong> for visual drag-and-drop customization from Company &gt; PDF Editor.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Advanced PDF customization requires the <strong>Pro</strong> plan or higher.</p></div><h2 id="team-members" tabindex="-1">Team members <a class="header-anchor" href="#team-members" aria-label="Permalink to &quot;Team members&quot;">​</a></h2><p>View and manage your team from the company page. See <a href="/settings/team">Team Management</a> for details.</p>',39)])])}const h=t(r,[["render",i]]);export{g as __pageData,h as default};
